#!/usr/bin/env node

/**
 * Intent Detector Module
 * 
 * Provides heuristic rules to translate natural language queries into structured search intent.
 * Analyzes user input to determine search type, filters, and preferences.
 */

/**
 * Detect intent from a natural language query
 * 
 * @param {string} query - The natural language search query
 * @returns {Object} Structured search intent with type, filters, and preferences
 */
function detectIntent(query) {
  const normalizedQuery = query.trim().toLowerCase();
  
  // Initialize intent structure
  const intent = {
    originalQuery: query,
    type: 'search', // Default type
    query: normalizedQuery,
    filters: {},
    preferences: {}
  };
  
  // Detect search type based on keywords
  intent.type = detectSearchType(normalizedQuery);
  
  // Extract filters based on query patterns
  intent.filters = extractFilters(normalizedQuery, intent.type);
  
  // Extract preferences (limit, sort, etc.)
  intent.preferences = extractPreferences(normalizedQuery);
  
  // For search types, extract the actual search terms
  if (intent.type === 'search') {
    intent.query = extractSearchTerms(normalizedQuery, intent.filters);
  }
  
  return intent;
}

/**
 * Detect the type of search based on query keywords
 * 
 * @param {string} query - Normalized query string
 * @returns {string} The detected search type
 */
function detectSearchType(query) {
  const searchTypePatterns = {
    'tags': /\b(tags|tag|etichette|etichetta|categoria|categorie)\b/,
    'type': /\b(type|tipo|tipologia|tipologie|categoria|categoría)\b/,
    'language': /\b(language|lingua|linguaggio|lang|langue)\b/,
    'project': /\b(project|progetto|progetti|cross-project|cross project)\b/,
    'exact': /^\s*["'].*["']\s*$/, // Quoted string
    'prefix': /\b(for|prefix|prefisso|prefixe)\b/,
    'contains': /\b(contains|contiene|includes|include)\b/,
    'starts': /\b(starts|inizi|comincia|begin)\b/,
    'fuzzy': /\b(fuzzy|approssimativo|similare|fuzzi)\b/,
    // Code placement patterns
    'script': /\b(cli|command|script|scripting|esecuzione|esecuzione)\b/,
    'utility': /\b(utility|helper|aiuto|help|funzione|function|libreria|librerias)\b/,
    'component': /\b(component|componente|ui|interface|interfaccia|widget)\b/,
    'test': /\b(test|testing|prove|testare|suite|test suite)\b/,
    'config': /\b(config|configuration|configurazione|configuratione|settings|impostazioni)\b/,
    'documentation': /\b(documentation|documentazione|docs|wiki|manuale)\b/,
    'snippet': /\b(snippet|pezzo|tratto|porzione)\b/,
    'example': /\b(example|esempio|esempi|sample|campioni|demo)\b/
  };
  
  for (const [type, pattern] of Object.entries(searchTypePatterns)) {
    if (pattern.test(query)) {
      return type;
    }
  }
  
  return 'search';
}

/**
 * Extract filters from the query
 * 
 * @param {string} query - Normalized query string
 * @param {string} searchType - The detected search type
 * @returns {Object} Object containing filter key-value pairs
 */
function extractFilters(query, searchType) {
  const filters = {};
  
  // Extract language filter
  const langPatterns = {
    'javascript': /\b(javascript|js|js\.|\.js)\b/,
    'typescript': /\b(typescript|ts|\.ts)\b/,
    'python': /\b(python|py|\.py)\b/,
    'go': /\b(go|golang|\.go)\b/,
    'rust': /\b(rust|rs|\.rs)\b/,
    'java': /\b(java|\.java)\b/,
    'c': /\b(c|\.c)\b/,
    'cpp': /\b(c\+\+|cpp|\.cpp|\.cc)\b/,
    'c#': /\b(c#|c\#|\.cs)\b/,
    'ruby': /\b(ruby|rb|\.rb)\b/,
    'php': /\b(php|\.php)\b/,
    'html': /\b(html|\.html|\.htm)\b/,
    'css': /\b(css|\.css)\b/,
    'sql': /\b(sql|\.sql)\b/,
    'json': /\b(json|\.json)\b/,
    'yaml': /\b(yaml|yml|\.yaml|\.yml)\b/,
    'markdown': /\b(markdown|md|\.md)\b/,
    'shell': /\b(shell|bash|sh|\.sh)\b/,
    'docker': /\b(docker|dockerfile|\.dockerfile)\b/,
    'other': /\b(other|altro|diverso)\b/
  };
  
  for (const [lang, pattern] of Object.entries(langPatterns)) {
    if (pattern.test(query)) {
      filters.language = lang;
      break;
    }
  }
  
  // Extract type filter
  const typePatterns = {
    'snippet': /\bsnippet\b/,
    'config': /\b(config|configuration|configurazione|configuratione)\b/,
    'example': /\b(example|esempio|esempi|sample|campione|campioni)\b/,
    'template': /\b(template|modello|modelli)\b/,
    'documentation': /\b(documentation|documentazione|docs)\b/,
    'code': /\b(code|codice)\b/,
    'script': /\b(script|scripting)\b/,
    'utility': /\b(utility|utilità|utilità|utils|utils)\b/,
    'helper': /\b(helper|aiuto|aiuto|help)\b/,
    'library': /\b(library|libreria|librerias|lib)\b/,
    'framework': /\b(framework|frameworks|cornice|cornici)\b/,
    'tool': /\b(tool|strumento|strumenti)\b/,
    'test': /\b(test|testing|prove|testare)\b/,
    'build': /\b(build|costruzione|compilazione|builds)\b/,
    'deploy': /\b(deploy|deployment|deployment|deployments|distribuzione|distribuzioni)\b/,
    'ci': /\b(ci|cd|continuous integration|continuous deployment|integrazione continua|distribuzione continua)\b/,
    'docker': /\b(docker|container|containers|containerizzazione|containerizzazione)\b/,
    'database': /\b(database|db|sql|nosql|data|dati)\b/,
    'api': /\b(api|rest|graphql|grpc|endpoint)\b/,
    'frontend': /\b(frontend|front-end|interface|interfaccia|ui|ux)\b/,
    'backend': /\b(backend|back-end|server|server-side|lato server)\b/,
    'devops': /\b(devops|dev-ops)\b/,
    'security': /\b(security|sicurezza|protezione|security|safeguard|safeguards)\b/,
    'performance': /\b(performance|prestazioni|performance|optimization|ottimizzazione)\b/,
    'other': /\b(other|altro|diverso|generico|generic)\b/
  };
  
  for (const [type, pattern] of Object.entries(typePatterns)) {
    if (pattern.test(query)) {
      filters.type = type;
      break;
    }
  }
  
  // Extract tag filters
  const tagPatterns = {
    'react': /\b(react|react\.js|@react)\b/,
    'vue': /\b(vue|vue\.js|@vue)\b/,
    'angular': /\b(angular|@angular)\b/,
    'next': /\b(next|next\.js|@next)\b/,
    'svelte': /\b(svelte|@svelte)\b/,
    'express': /\b(express|@express)\b/,
    'nest': /\b(nest|@nestjs)\b/,
    'fastapi': /\b(fastapi|fastapi)\b/,
    'django': /\b(django|@django)\b/,
    'flask': /\b(flask|@flask)\b/,
    'pytest': /\b(pytest|@pytest)\b/,
    'jest': /\b(jest|@jest)\b/,
    'vitest': /\b(vitest|@vitest)\b/,
    'mocha': /\b(mocha|@mocha)\b/,
    'cypress': /\b(cypress|@cypress)\b/,
    'playwright': /\b(playwright|@playwright)\b/,
    'tailwind': /\b(tailwind|@tailwindcss)\b/,
    'bootstrap': /\b(bootstrap|@bootstrap)\b/,
    'material': /\b(material|@material|@mui)\b/,
    'graphql': /\b(graphql|@apollo|urql|@urql)\b/,
    'prisma': /\b(prisma|@prisma)\b/,
    'drizzle': /\b(drizzle|@drizzle)\b/,
    'mongoose': /\b(mongoose|@mongoose)\b/,
    'sequelize': /\b(sequelize|@sequelize)\b/,
    'typeorm': /\b(typeorm|@typeorm)\b/,
    'redis': /\b(redis|@redis)\b/,
    'elasticsearch': /\b(elasticsearch|elastic|@elastic)\b/,
    'postgres': /\b(postgres|postgresql|@postgres)\b/,
    'mysql': /\b(mysql|@mysql)\b/,
    'mongodb': /\b(mongodb|@mongodb|mongo)\b/,
    'aws': /\b(aws|amazon web services|@aws|@amazonaws)\b/,
    'google': /\b(google|gcp|google cloud|@google)\b/,
    'azure': /\b(azure|microsoft azure|@azure)\b/,
    'docker': /\b(docker|@docker)\b/,
    'kubernetes': /\b(kubernetes|k8s|@kubernetes|@k8s)\b/,
    'terraform': /\b(terraform|@hashicorp)\b/,
    'github': /\b(github|@github)\b/,
    'gitlab': /\b(gitlab|@gitlab)\b/,
    'npm': /\b(npm|@npm)\b/,
    'yarn': /\b(yarn|@yarn)\b/,
    'pnpm': /\b(pnpm|@pnpm)\b/,
    'vite': /\b(vite|@vitejs)\b/,
    'webpack': /\b(webpack|@webpack)\b/,
    'babel': /\b(babel|@babel)\b/,
    'eslint': /\b(eslint|@eslint)\b/,
    'prettier': /\b(prettier|@prettier)\b/,
    'typescript': /\b(typescript|@typescript)\b/,
    'jest': /\b(jest|@jest)\b/,
    'testing': /\b(testing|test|tests|prove)\b/
  };
  
  const foundTags = [];
  for (const [tag, pattern] of Object.entries(tagPatterns)) {
    if (pattern.test(query)) {
      foundTags.push(tag);
    }
  }
  
  if (foundTags.length > 0) {
    filters.tags = foundTags;
  }
  
  // Extract project scope
  if (/\b(cross-project|cross project|multi-project|multi project|progetto|progetti)\b/.test(query)) {
    filters.crossProject = true;
  }
  
  return filters;
}

/**
 * Extract user preferences from the query
 * 
 * @param {string} query - Normalized query string
 * @returns {Object} Object containing user preferences
 */
function extractPreferences(query) {
  const preferences = {};
  
  // Extract limit (e.g., "limit 5", "top 10", "max 3")
  const limitMatch = query.match(/\b(limit|top|max|maximo|migliori|prima|prime)\b\s*\d+/);
  if (limitMatch) {
    const limitNum = parseInt(query.match(/\d+/)[0], 10);
    preferences.limit = limitNum;
  }
  
  // Extract sort preference
  if (/\b(sort|ordina|ordine|sorted|asc|desc|alphabetical|alfabetico)\b/.test(query)) {
    preferences.sort = 'alphabetical';
  }
  
  // Extract relevance preference
  if (/\b(relevant|relevante|top|best|migliore|più rilevante)\b/.test(query)) {
    preferences.sort = 'relevance';
  }
  
  // Extract pagination preference
  if (/\b(page|pagina|pagine|offset|paggina)\b/.test(query)) {
    preferences.pagination = true;
  }
  
  // Extract exact match preference
  if (/^["'].*["']$/.test(query)) {
    preferences.exact = true;
  }
  
  // Extract fuzzy match preference
  if (/\b(fuzzy|approximate|approssimativo|similare|fuzzi)\b/.test(query)) {
    preferences.fuzzy = true;
  }
  
  return preferences;
}

/**
 * Extract search terms from query after removing filter keywords
 * 
 * @param {string} query - Normalized query string
 * @param {Object} filters - Extracted filters
 * @returns {string} Clean search terms
 */
function extractSearchTerms(query, filters) {
  let terms = query;
  
  // Remove filter keywords and their values
  const filterKeywords = [
    'javascript', 'js', 'typescript', 'ts', 'python', 'py', 'go', 'golang',
    'rust', 'rs', 'java', 'c', 'cpp', 'c#', 'ruby', 'rb', 'php', 'html',
    'css', 'sql', 'json', 'yaml', 'yml', 'markdown', 'md', 'shell', 'bash',
    'sh', 'docker', 'dockerfile', 'other', 'snippet', 'config', 'configuration',
    'example', 'esempio', 'sample', 'template', 'modello', 'documentation',
    'documentazione', 'code', 'codice', 'script', 'utility', 'utils', 'helper',
    'help', 'library', 'libreria', 'framework', 'tool', 'strumento', 'test',
    'testing', 'build', 'deploy', 'ci', 'cd', 'database', 'db', 'api', 'frontend',
    'backend', 'devops', 'security', 'sicurezza', 'performance', 'prestazioni',
    'cross-project', 'multi-project', 'project', 'progetto', 'tags', 'tag',
    'type', 'tipo', 'language', 'lingua', 'limit', 'top', 'max', 'sort', 'order',
    'relevance', 'relevant', 'page', 'pagina', 'fuzzy', 'approximate', 'similare'
  ];
  
  // Remove known filter keywords
  filterKeywords.forEach(keyword => {
    const regex = new RegExp(`\\b${keyword}\\b`, 'gi');
    terms = terms.replace(regex, '');
  });
  
  // Clean up multiple spaces and trim
  terms = terms.replace(/\s+/g, ' ').trim();
  
  return terms;
}

/**
 * Generate a search query from structured intent
 * 
 * @param {Object} intent - The structured intent
 * @returns {string} Formatted search query string
 */
function generateQuery(intent) {
  const parts = [];
  
  // Add search terms
  if (intent.query) {
    parts.push(intent.query);
  }
  
  // Add filters
  if (intent.filters.language) {
    parts.push(`lang:${intent.filters.language}`);
  }
  
  if (intent.filters.type) {
    parts.push(`type:${intent.filters.type}`);
  }
  
  if (intent.filters.tags && intent.filters.tags.length > 0) {
    parts.push(`tags:${intent.filters.tags.join(',')}`);
  }
  
  if (intent.filters.crossProject) {
    parts.push('cross:true');
  }
  
  // Add preferences
  if (intent.preferences.limit) {
    parts.push(`limit:${intent.preferences.limit}`);
  }
  
  if (intent.preferences.sort) {
    parts.push(`sort:${intent.preferences.sort}`);
  }
  
  if (intent.preferences.exact) {
    parts.push('exact:true');
  }
  
  if (intent.preferences.fuzzy) {
    parts.push('fuzzy:true');
  }
  
  return parts.join(' ');
}

/**
 * Main execution - test the intent detector
 */
function main() {
  const testQueries = [
    'javascript code for React component',
    'typescript example with TypeScript and JSDoc',
    'Python utility function',
    'Go snippet for Kubernetes deployment',
    'Cross-project search for API endpoints',
    'Limit 5 top results for database query',
    'Sort by relevance for performance optimization',
    '"exact match" query',
    'fuzzy search for similar code',
    'HTML template with Tailwind CSS'
  ];
  
  console.log('🔍 Intent Detector Module');
  console.log('='.repeat(60));
  console.log('Testing intent detection with natural language queries:\n');
  
  testQueries.forEach(query => {
    const intent = detectIntent(query);
    console.log(`Original: "${query}"`);
    console.log('Detected Intent:');
    console.log(`  Type: ${intent.type}`);
    console.log(`  Query: ${intent.query || '(none)'}`);
    console.log(`  Filters: ${JSON.stringify(intent.filters) || '(none)'}`);
    console.log(`  Preferences: ${JSON.stringify(intent.preferences) || '(none)'}`);
    console.log(`  Generated: "${generateQuery(intent)}"`);
    console.log('-'.repeat(60));
  });
  
  console.log('\n✅ Intent detector module ready!');
}

// Export for use in other modules
module.exports = {
  detectIntent,
  detectSearchType,
  extractFilters,
  extractPreferences,
  extractSearchTerms,
  generateQuery
};

// Execute if run directly
if (require.main === module) {
  main();
}

#!/usr/bin/env node

/**
 * GSD + Qdrant CLI - Main entry point
 */

const { spawnSync } = require('child_process');
const http = require('http');
const fs = require('fs');
const { existsSync, readFileSync, mkdirSync, writeFileSync, copyFileSync, rmSync, unlinkSync } = fs;
const { join, dirname, extname, basename } = require('path');
const readline = require('readline');

const PROJECT_ROOT = process.cwd();
const ROOT_PKG = join(PROJECT_ROOT, 'package.json');
const API_PKG = join(PROJECT_ROOT, 'apps', 'api', 'package.json');
const CLI_ROOT = __dirname;
const TOOL_DIR_NAME = 'gsd-qdrant-knowledge';
const TOOL_DIR = join(PROJECT_ROOT, TOOL_DIR_NAME);
const TOOL_MCP_FILE = join(TOOL_DIR, 'mcp.json');
const ROOT_MCP_FILE = join(PROJECT_ROOT, '.mcp.json');
const TOOL_MARKER = 'managedBy';
const TOOL_MARKER_VALUE = 'gsd-qdrant-knowledge';
const MCP_SERVER_NAME = 'gsd-qdrant';

const DEFAULT_QDRANT_URL = 'http://localhost:6333';
const QDRANT_HEALTHZ_PATH = '/healthz';

/**
 * Resolve the actual path to gsd-qdrant-mcp/index.js.
 * Tries: local node_modules → global npm root → relative (dev symlink).
 * Returns null if nothing is found.
 */
function getMcpServerPath() {
  // 1. Local resolution
  try {
    const resolved = require.resolve('gsd-qdrant-knowledge');
    const mcpPath = join(dirname(resolved), 'src', 'gsd-qdrant-mcp', 'index.js');
    if (existsSync(mcpPath)) return mcpPath;
  } catch (_) {}

  // 2. Global npm root resolution
  try {
    const globalModules = getGlobalNodeModulesPath();
    if (globalModules) {
      const mcpPath = join(globalModules, 'gsd-qdrant-knowledge', 'src', 'gsd-qdrant-mcp', 'index.js');
      if (existsSync(mcpPath)) return mcpPath;
    }
  } catch (_) {}

  // 3. Relative path from CLI root (development / symlink)
  const cliRoot = __dirname;
  const candidates = [
    join(cliRoot, 'gsd-qdrant-mcp', 'index.js'),
    join(dirname(cliRoot), 'src', 'gsd-qdrant-mcp', 'index.js'),
  ];
  for (const p of candidates) {
    if (existsSync(p)) return p;
  }

  return null;
}

function findFileInCliRoot(filename) {
  const pathInCliRoot = join(CLI_ROOT, filename);
  if (existsSync(pathInCliRoot)) return pathInCliRoot;
  return join(dirname(CLI_ROOT), filename);
}

function getExtensionForLanguage(language) {
  if (!language) return '.js';
  const lang = language.toLowerCase();
  const extensions = {
    javascript: '.js', js: '.js', typescript: '.ts', ts: '.ts', python: '.py', py: '.py',
    go: '.go', rust: '.rs', java: '.java', c: '.c', cpp: '.cpp', 'c++': '.cpp', 'c#': '.cs',
    ruby: '.rb', php: '.php', swift: '.swift', kt: '.kt', kotlin: '.kt', scala: '.scala',
    html: '.html', css: '.css', scss: '.scss', less: '.less', json: '.json', yaml: '.yaml',
    yml: '.yml', markdown: '.md', md: '.md', sql: '.sql', sh: '.sh', bash: '.sh', zsh: '.zsh',
    powershell: '.ps1', r: '.r', rscript: '.r'
  };
  return extensions[lang] || '.js';
}

function run(command, args, options = {}) {
  return spawnSync(command, args, {
    stdio: 'inherit',
    shell: true,
    env: process.env,
    ...options,
  });
}

const REQUIRED_PACKAGES = [
  '@qdrant/js-client-rest',
  '@xenova/transformers',
  '@modelcontextprotocol/sdk',
  'zod'
];

function findPackagePath() {
  if (existsSync(API_PKG)) return API_PKG;
  if (existsSync(ROOT_PKG)) return ROOT_PKG;
  return null;
}

function getGlobalNodeModulesPath() {
  try {
    const result = spawnSync('npm', ['root', '-g'], { shell: true });
    if (result.status === 0) return result.stdout.toString().trim();
  } catch (_) {}
  return null;
}

function areRequiredPackagesInstalled(projectRoot, pkgPath) {
  try {
    const pkg = JSON.parse(readFileSync(pkgPath, 'utf8'));
    const declaredDeps = { ...(pkg.dependencies || {}), ...(pkg.devDependencies || {}) };

    for (const dep of REQUIRED_PACKAGES) {
      if (!declaredDeps[dep]) continue;
      try {
        require.resolve(dep, { paths: [projectRoot] });
        continue;
      } catch (_) {
        const globalPath = getGlobalNodeModulesPath();
        if (globalPath) {
          try {
            require.resolve(dep, { paths: [globalPath] });
            continue;
          } catch (_) {}
        }
        return false;
      }
    }

    return true;
  } catch (_) {
    return false;
  }
}

function installDependencies(pkgPath) {
  if (areRequiredPackagesInstalled(PROJECT_ROOT, pkgPath)) {
    console.log('📦 Dependencies: ok');
    return 'ok';
  }

  console.log('📦 Dependencies: installing missing packages...');
  const result = run('npm', ['install', ...REQUIRED_PACKAGES], { cwd: PROJECT_ROOT });
  if (result.status !== 0) {
    console.error('❌ Dependency installation failed.');
    process.exit(result.status || 1);
  }
  return 'installed';
}

function readJsonFile(path, fallback) {
  try {
    return JSON.parse(readFileSync(path, 'utf8'));
  } catch (_) {
    return fallback;
  }
}

function writeJsonFile(path, value) {
  writeFileSync(path, JSON.stringify(value, null, 2) + '\n', 'utf8');
}

// ─── QDrant health check ──────────────────────────────────────────────

/**
 * Check if a QDrant server is healthy at the given URL.
 * Qdrant v1.x returns plain text "healthz check passed" on /healthz.
 * Returns true if the response indicates health.
 * @param {string} url - Base URL (e.g. http://localhost:6333)
 * @returns {Promise<boolean>}
 */
async function checkQdrantHealth(url) {
  return new Promise((resolve) => {
    const req = http.get(`${url}${QDRANT_HEALTHZ_PATH}`, (res) => {
      let body = '';
      res.on('data', (chunk) => { body += chunk; });
      res.on('end', () => {
        // Qdrant v1.x returns plain text "healthz check passed"
        const ok = body.includes('ok') || body.includes('passed');
        resolve(ok);
      });
    });
    req.on('error', () => { resolve(false); });
    req.setTimeout(3000, () => { req.destroy(); resolve(false); });
  });
}

/**
 * Check if QDrant is running. Exits with error if not available.
 * @returns {{ url: string }}
 */
async function ensureQdrantRunning() {
  const qdrantUrl = process.env.QDRANT_URL || DEFAULT_QDRANT_URL;

  const healthy = await checkQdrantHealth(qdrantUrl);
  if (healthy) {
    console.log('✅ QDrant server detected at ' + qdrantUrl);
    return { url: qdrantUrl };
  }

  console.error('❌ QDrant is not running at ' + qdrantUrl);
  console.error('   Start it with: docker run -d --name qdrant -p 6333:6333 qdrant/qdrant');
  console.error('   Or set QDRANT_URL environment variable to your QDrant instance.');
  process.exit(1);
}

function createGsdQdrantDirectory(projectRoot) {
  const stateFile = join(TOOL_DIR, '.qdrant-sync-state.json');
  const packageFile = join(TOOL_DIR, 'package.json');
  const indexFile = join(TOOL_DIR, 'index.js');

  if (!existsSync(TOOL_DIR)) {
    mkdirSync(TOOL_DIR, { recursive: true });
    console.log(`📂 Created directory: ${TOOL_DIR_NAME}/`);
  }

  if (!existsSync(stateFile)) {
    writeJsonFile(stateFile, { lastSync: null, indexed: {} });
    console.log(`📝 Created: ${TOOL_DIR_NAME}/.qdrant-sync-state.json`);
  }

  if (!existsSync(packageFile)) {
    writeFileSync(packageFile, JSON.stringify({ type: 'commonjs' }, null, 2) + '\n', 'utf8');
    console.log(`📝 Created: ${TOOL_DIR_NAME}/package.json`);
  }

  if (!existsSync(indexFile)) {
    const templateIndexFile = findFileInCliRoot('gsd-qdrant-template.js');
    copyFileSync(templateIndexFile, indexFile);
    console.log(`📝 Created: ${TOOL_DIR_NAME}/index.js`);
  }
}

function ensureToolMcpConfig() {
  const mcpPath = getMcpServerPath();
  if (!mcpPath) {
    console.warn('⚠️  Cannot resolve gsd-qdrant-mcp path. Please reinstall the package.');
    return;
  }

  const config = {
    [TOOL_MARKER]: TOOL_MARKER_VALUE,
    serverName: MCP_SERVER_NAME,
    mcpServers: {
      [MCP_SERVER_NAME]: {
        command: 'node',
        args: [mcpPath],
        cwd: '.',
        env: {
          QDRANT_URL: process.env.QDRANT_URL || 'http://localhost:6333',
          COLLECTION_NAME: process.env.COLLECTION_NAME || 'gsd_memory',
          VECTOR_NAME: process.env.VECTOR_NAME || 'fast-all-minilm-l6-v2'
        }
      }
    }
  };
  const existed = existsSync(TOOL_MCP_FILE);
  writeJsonFile(TOOL_MCP_FILE, config);
  console.log(`${existed ? '📝 Updated' : '📝 Created'}: ${TOOL_DIR_NAME}/mcp.json`);
}

function ensureRootMcpRegistration() {
  const mcpPath = getMcpServerPath();
  if (!mcpPath) {
    console.warn('⚠️  Cannot resolve gsd-qdrant-mcp path. Please reinstall the package.');
    return;
  }

  const current = readJsonFile(ROOT_MCP_FILE, { mcpServers: {} });
  const mcpServers = current.mcpServers && typeof current.mcpServers === 'object' ? current.mcpServers : {};
  const desired = {
    command: 'node',
    args: [mcpPath],
    cwd: '.',
    env: {
      QDRANT_URL: process.env.QDRANT_URL || 'http://localhost:6333',
      COLLECTION_NAME: process.env.COLLECTION_NAME || 'gsd_memory',
      VECTOR_NAME: process.env.VECTOR_NAME || 'fast-all-minilm-l6-v2'
    }
  };

  const previous = JSON.stringify(mcpServers[MCP_SERVER_NAME] || null);
  const next = JSON.stringify(desired);
  if (previous === next) {
    console.log('ℹ️  MCP server already registered in .mcp.json');
    return;
  }

  mcpServers[MCP_SERVER_NAME] = desired;
  current.mcpServers = mcpServers;
  writeJsonFile(ROOT_MCP_FILE, current);
  console.log('📝 Updated: .mcp.json');
}

function removeRootMcpRegistration() {
  if (!existsSync(ROOT_MCP_FILE)) return;
  const current = readJsonFile(ROOT_MCP_FILE, null);
  if (!current || !current.mcpServers || !current.mcpServers[MCP_SERVER_NAME]) return;
  delete current.mcpServers[MCP_SERVER_NAME];
  if (Object.keys(current.mcpServers).length === 0) {
    unlinkSync(ROOT_MCP_FILE);
    console.log('🧹 Removed: .mcp.json');
    return;
  }
  writeJsonFile(ROOT_MCP_FILE, current);
  console.log('🧹 Updated: .mcp.json');
}

async function addToGitignore(projectRoot, entry) {
  const gitignorePath = join(projectRoot, '.gitignore');
  if (!existsSync(gitignorePath)) {
    console.log('ℹ️  .gitignore not found, skipping');
    return;
  }
  const content = await fs.promises.readFile(gitignorePath, 'utf8');
  const lines = content.split('\n');
  if (lines.some(line => line.trim() === entry)) {
    console.log('ℹ️  Entry already in .gitignore');
    return;
  }
  await fs.promises.writeFile(gitignorePath, content + '\n' + entry + '\n', 'utf8');
  console.log(`📝 Added '${entry}' to .gitignore`);
}

async function removeFromGitignore(projectRoot, entry) {
  const gitignorePath = join(projectRoot, '.gitignore');
  if (!existsSync(gitignorePath)) return;
  const content = await fs.promises.readFile(gitignorePath, 'utf8');
  const next = content
    .split('\n')
    .filter(line => line.trim() !== entry)
    .join('\n')
    .replace(/\n{3,}/g, '\n\n');
  if (next !== content) {
    await fs.promises.writeFile(gitignorePath, next, 'utf8');
    console.log(`🧹 Removed '${entry}' from .gitignore`);
  }
}

async function uninstallProjectArtifacts() {
  // Step 1: Clean up Qdrant collection FIRST — delete all points for this project
  // Uses server-side filter (scroll ignores unknown params) so only matching points are fetched.
  const qdrantUrl = process.env.QDRANT_URL || DEFAULT_QDRANT_URL;
  try {
    const templatePath = findFileInCliRoot('gsd-qdrant-template.js');
    if (templatePath) {
      const { GSDKnowledgeSync } = require(templatePath);
      // Override QDRANT_URL env for this instance
      const sync = new GSDKnowledgeSync();
      sync.client = new (require('@qdrant/js-client-rest').QdrantClient)({ url: qdrantUrl });
      const deleted = await sync.deleteAllProjectPoints();
      if (deleted > 0) {
        console.log(`🧹 Qdrant: Deleted ${deleted} point(s) for project '${sync.projectName}'`);
      } else {
        console.log(`ℹ️  Qdrant: No points found for project '${sync.projectName}'`);
      }
    }
  } catch (err) {
    console.warn('⚠️  Qdrant cleanup skipped (collection may not exist or be unreachable):', err.message);
  }

  // Step 2: Remove local artifacts
  removeRootMcpRegistration();

  const hooksDir = join(PROJECT_ROOT, '.git', 'hooks');
  if (existsSync(hooksDir)) {
    for (const hook of ['post-commit.sh', 'post-commit.bat']) {
      const hookPath = join(hooksDir, hook);
      if (existsSync(hookPath)) {
        // Verifica che sia il nostro hook prima di rimuovere
        try {
          const content = readFileSync(hookPath, 'utf8');
          if (content.includes('gsd-qdrant-knowledge')) {
            unlinkSync(hookPath);
            console.log(`🧹 Removed: .git/hooks/${hook}`);
          }
        } catch (_) {}
      }
    }
  }

  if (existsSync(TOOL_DIR)) {
    rmSync(TOOL_DIR, { recursive: true, force: true });
    console.log(`🧹 Removed: ${TOOL_DIR_NAME}/`);
  }

 // Remove auto-retrieve instructions from project-level KNOWLEDGE.md
  const instructionsScript = findFileInCliRoot('knowledge-instructions.js');
  if (existsSync(instructionsScript)) {
    try {
      const { removeKnowledgeInstructions } = require(instructionsScript);
      removeKnowledgeInstructions({ cwd: PROJECT_ROOT });
    } catch (err) {
      console.warn('⚠️  Knowledge instructions cleanup failed:', err.message);
    }
  }
}

function installPostCommitHook() {
  const hooksDir = join(PROJECT_ROOT, '.git', 'hooks');
  if (!existsSync(hooksDir)) return;

  const isWindows = process.platform === 'win32';
  const hookName = isWindows ? 'post-commit.bat' : 'post-commit.sh';
  const hookPath = join(hooksDir, hookName);

  // Cerca il template in ordine: src/hooks/ → root/hooks/
  const templates = [
    join(CLI_ROOT, 'hooks', hookName),
    join(dirname(CLI_ROOT), 'src', 'hooks', hookName),
    join(PROJECT_ROOT, 'src', 'hooks', hookName),
  ];

  let hookContent = null;
  for (const t of templates) {
    if (existsSync(t)) {
      hookContent = readFileSync(t, 'utf8');
      break;
    }
  }

  if (!hookContent) return;

  try {
    const existing = readFileSync(hookPath, 'utf8');
    if (existing === hookContent) return;
  } catch (_) {}

  writeFileSync(hookPath, hookContent, { mode: isWindows ? undefined : 0o755 });
  console.log(`📝 Post-commit hook installed (${hookName})`);
}

async function bootstrapProject() {
  console.log('🚀 GSD + Qdrant CLI\n');
  createGsdQdrantDirectory(PROJECT_ROOT);

  // Ensure auto-retrieve instructions are in project-level KNOWLEDGE.md (safe to run multiple times)
  const instructionsScript = findFileInCliRoot('knowledge-instructions.js');
  if (existsSync(instructionsScript)) {
    try {
      const { ensureKnowledgeInstructions } = require(instructionsScript);
      ensureKnowledgeInstructions();
    } catch (err) {
      console.warn('⚠️  Knowledge instructions setup failed:', err.message);
    }
  }

  const installExtensionScript = findFileInCliRoot('install-gsd-extension.js');
  if (existsSync(installExtensionScript)) {
    const installResult = spawnSync('node', [installExtensionScript], {
      cwd: PROJECT_ROOT,
      stdio: 'inherit',
      shell: false
    });
    if (installResult.status !== 0) {
      console.error('⚠️  GSD extension installation failed');
    }
  }

  ensureToolMcpConfig();
  ensureRootMcpRegistration();

  const pkgPath = findPackagePath();
  if (!pkgPath) {
    console.error('❌ No package.json found. Are you in a Node.js project?');
    process.exit(1);
  }

  console.log(`📁 Project: ${basename(PROJECT_ROOT)}`);
  installDependencies(pkgPath);
  run('node', [findFileInCliRoot('setup-from-templates.js')], { cwd: PROJECT_ROOT });

  // Install post-commit hook for automatic knowledge sync
  installPostCommitHook();

  await addToGitignore(PROJECT_ROOT, `${TOOL_DIR_NAME}/`);

  // Ensure QDrant is running before sync
  const qdrantResult = await ensureQdrantRunning();

  // Run sync with the correct QDRANT_URL in env
  const syncScript = findFileInCliRoot('sync-knowledge.js');
  const syncResult = spawnSync('node', [syncScript], {
    cwd: PROJECT_ROOT,
    stdio: 'inherit',
    env: { ...process.env },
  });
  if (syncResult.status !== 0) {
    console.error('\n❌ Initial knowledge sync failed. Collections may be empty.');
    process.exit(syncResult.status || 1);
  }

  console.log('\n✅ Ready');
  process.exit(0);
}

async function main() {
  const args = process.argv.slice(2);

  if (args[0] === '--version' || args[0] === '-v') {
    const pkgPath = findFileInCliRoot('package.json');
    const pkg = JSON.parse(readFileSync(pkgPath, 'utf8'));
    console.log(`gsd-qdrant-knowledge v${pkg.version}`);
    process.exit(0);
  }

  if (args[0] === 'uninstall') {
    uninstallProjectArtifacts();
    await removeFromGitignore(PROJECT_ROOT, `${TOOL_DIR_NAME}/`);
    console.log('\n✅ Uninstall complete');
    return;
  }

  if (args.length === 0) {
    await bootstrapProject();
    return;
  }

  if (args[0] === 'context') {
    const { GSDKnowledgeSync } = require(findFileInCliRoot('gsd-qdrant-template.js'));
    const query = args[1] || '';
    const project_id = basename(PROJECT_ROOT);

    if (!query) {
      console.log('❌ Please provide a query for context building.');
      console.log('Usage: gsd-qdrant-knowledge context <query>');
      process.exit(1);
    }

    const sync = new GSDKnowledgeSync();
    await sync.init();
    const vector = await sync.embedText(query);

    // Prefetch-based query: first do a broad search to gather candidates,
    // then refine with score threshold for high-relevance results only.
    const t0 = Date.now();
    const prefetchLimit = 50;
    const finalLimit = 10;
    const SCORE_THRESHOLD = 0.65;

    let hits = [];
    try {
      // Prefetch: broad vector search (no filter, wide limit)
      const prefetchResults = await sync.client.search(sync.collectionName, {
        vector: { name: sync.vectorName, vector },
        prefetch: {
          query: { name: sync.vectorName, vector },
          limit: prefetchLimit,
        },
        limit: finalLimit,
        score_threshold: SCORE_THRESHOLD,
        with_payload: true,
        with_vector: false,
      });
      hits = prefetchResults;
    } catch (prefetchErr) {
      // Fallback: plain search if prefetch is not supported in this Qdrant version
      console.warn('[qdrant] prefetch not supported, falling back to search');
      hits = await sync.client.search(sync.collectionName, {
        vector: { name: sync.vectorName, vector },
        limit: finalLimit,
        score_threshold: SCORE_THRESHOLD,
        with_payload: true,
        with_vector: false,
      });
    }

    const elapsed = Date.now() - t0;
    console.log('[qdrant] prefetch: %d results in %dms', hits.length, elapsed);

    const ranked = hits.map(hit => ({ ...hit.payload, score: hit.score }));
    console.log(JSON.stringify({ query, project_id, results: ranked }, null, 2));
    return;
  }

  if (args[0] === 'snippet' && args[1] === 'search') {
    const query = args[2] || '';
    const options = {};

    for (let i = 3; i < args.length; i++) {
      if (args[i].startsWith('--')) {
        const key = args[i].slice(2);
        const value = args[i + 1];
        if (key === 'tags' && value) options.tags = value.split(',');
        if (key === 'language' && value) options.language = value;
        if (key === 'type' && value) options.type = value;
        if (key === 'context') options.withContext = true;
        if (key === 'limit' && value) options.limit = parseInt(value, 10);
      }
    }

    if (!query) {
      console.log('❌ Please provide a search query.');
      console.log('Usage: gsd-qdrant-knowledge snippet search <query> [--tags <tag1,tag2>] [--language <lang>] [--type <type>] [--context] [--limit <n>]');
      process.exit(1);
    }

    const runtimeSyncPath = join(PROJECT_ROOT, TOOL_DIR_NAME, 'index.js');
    const useQdrant = existsSync(runtimeSyncPath);
    let sorted = [];

    if (useQdrant) {
      try {
        const { GSDKnowledgeSync } = require(runtimeSyncPath);
        const sync = new GSDKnowledgeSync();
        await sync.init();
        sorted = await sync.searchWithContext(query, {
          limit: options.limit || 10,
          type: options.type || undefined,
        });
      } catch (err) {
        console.log('⚠️  Qdrant search failed, falling back to local database:', err.message);
      }
    }

    if (sorted.length === 0) {
      const snippetRanking = require(findFileInCliRoot('snippet-ranking'));
      const snippets = snippetRanking.loadDatabase();
      const filtered = snippetRanking.filterAndRankSnippets(snippets, query, options);
      sorted = snippetRanking.sortSnippetsByRelevance(filtered);
    }

    console.log('🔍 Snippet Search');
    console.log('='.repeat(50));
    console.log(`Query: "${query}"`);
    if (options.withContext) console.log('With Context: Yes');
    console.log(`Found ${sorted.length} results:`);

    sorted.forEach((result, i) => {
      console.log(`  ${i + 1}. ${result.path || result.name} (score: ${result.score || result.relevanceScore})`);
      console.log(`     Type: ${result.type}, Scope: ${result.scope}`);
      if (result.milestone || result.slice || result.task) {
        console.log(`     GSD: ${result.milestone || ''} ${result.slice || ''} ${result.task || ''}`.trim());
      }
      console.log(`     ${result.content?.slice(0, 200) || 'No content'}`);
      if (result.context && result.context.length > 0) {
        console.log(`     Context: ${result.context.length} related documents`);
        result.context.forEach(ctx => {
          console.log(`       - ${ctx.source} (${ctx.ids.length} IDs: ${ctx.ids.slice(0, 3).join(', ')})`);
        });
      }
    });

    console.log('='.repeat(50));
    console.log('✅ Search complete!');
    return;
  }

  if (args[0] === 'snippet' && args[1] === 'apply') {
    const query = args[2] || '';

    if (!query) {
      console.log('❌ Please provide a query for the snippet to apply.');
      console.log('Usage: gsd-qdrant-knowledge snippet apply <query>');
      process.exit(1);
    }

    const snippetRanking = require(findFileInCliRoot('snippet-ranking'));
    const intentDetector = require(findFileInCliRoot('intent-detector'));
    const contextAnalyzer = require(findFileInCliRoot('context-analyzer'));
    const intent = intentDetector.detectIntent(query);
    const snippets = snippetRanking.loadDatabase();
    const filtered = snippetRanking.filterAndRankSnippets(snippets, intent.query, {
      tags: intent.filters.tags || [],
      language: (intent.filters.language && !intent.filters.tags?.includes(intent.filters.language)) ? intent.filters.language : '',
      type: intent.filters.type || '',
      crossProject: intent.filters.crossProject || true
    });
    const sorted = snippetRanking.sortSnippetsByRelevance(filtered);

    console.log('📝 Snippet Apply');
    console.log('='.repeat(50));
    console.log(`Query: "${query}"`);

    if (sorted.length === 0) {
      console.log('\n⚠️  No matching snippets found.');
      console.log('='.repeat(50));
      console.log('✅ Search complete (no results)');
      process.exit(0);
    }

    const topMatch = sorted[0];
    const projectContext = contextAnalyzer.analyzeProjectContext();
    const placement = contextAnalyzer.recommendCodePlacement(topMatch.description || query, projectContext);
    const fileExtension = getExtensionForLanguage(topMatch.language);
    const baseFileName = topMatch.sourceFile ? basename(topMatch.sourceFile).replace(extname(topMatch.sourceFile), '') : 'snippet';
    const fileName = `${baseFileName}${fileExtension}`;
    const filePath = join(PROJECT_ROOT, placement.path, fileName);

    let willOverwrite = false;
    if (existsSync(filePath)) {
      const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
      const timeout = setTimeout(() => {
        console.log('\n⚠️  No user input received, defaulting to overwrite.');
        willOverwrite = true;
        rl.close();
      }, 1000);

      await new Promise((resolve) => {
        rl.question('Would you like to overwrite it? (y/N): ', (answer) => {
          clearTimeout(timeout);
          const response = answer.toLowerCase().trim();
          willOverwrite = response === 'y' || response === 'yes';
          rl.close();
          resolve();
        });
      });

      if (!willOverwrite) {
        console.log('❌ File not created (user declined to overwrite).');
        console.log('✅ Operation cancelled.');
        process.exit(0);
      }
    } else {
      const dirPath = dirname(filePath);
      if (!existsSync(dirPath)) mkdirSync(dirPath, { recursive: true });
    }

    writeFileSync(filePath, topMatch.content, 'utf8');
    console.log(`✅ File created successfully: ${filePath}`);
    return;
  }

  await bootstrapProject();
}

main();

#!/usr/bin/env node

const { QdrantClient } = require('@qdrant/js-client-rest');
const { promises: fs, existsSync } = require('fs');
const { join, basename, extname, relative, dirname } = require('path');
const crypto = require('crypto');

const QDRANT_URL = process.env.QDRANT_URL || 'http://localhost:6333';
const PROJECT_ROOT = process.cwd();
const STATE_FILE = join(PROJECT_ROOT, 'gsd-qdrant-knowledge', '.qdrant-sync-state.json');

const EXCLUDED_DIRS = new Set([
  '.git', 'node_modules', 'vendor', 'bower_components', '.next', 'dist', 'build', 'coverage', '.turbo', '.vercel', '.idea', '.vscode', '.bg-shell', 'gsd-qdrant-knowledge',
]);
const CODE_EXTENSIONS = new Set([
  '.js', '.jsx', '.ts', '.tsx', '.mjs', '.cjs', '.py', '.rb', '.php', '.go', '.rs', '.java', '.kt', '.scala', '.cs', '.html', '.css', '.scss', '.sass', '.less', '.sql', '.sh', '.bash', '.zsh', '.ps1', '.json', '.yaml', '.yml', '.toml', '.xml', '.swift', '.dart', '.vue', '.svelte', '.astro'
]);
const EXCLUDED_FILE_EXTENSIONS = new Set([
  '.png', '.jpg', '.jpeg', '.gif', '.webp', '.svg', '.ico', '.pdf', '.zip', '.gz', '.tar', '.mp3', '.mp4', '.mov', '.woff', '.woff2', '.ttf', '.env', '.lock', '.log'
]);

// Files managed by GSD locally - exclude from Qdrant to avoid duplicate context
// GSD is the source of truth for the current project; Qdrant is an enhancer for cross-project sharing
const GSD_PROJECT_FILES = new Set([
  'STATE.md',
  'REQUIREMENTS.md',
  'DECISIONS.md',
  'KNOWLEDGE.md',
  'PROJECT.md',
  'FUTURE-REQUIREMENTS.md'
]);

class GSDKnowledgeSync {
  constructor() {
    this.client = new QdrantClient({ url: QDRANT_URL });
    this.projectName = basename(PROJECT_ROOT);
    this.collectionName = 'gsd_memory'; // Unified collection for all projects
    this.vectorName = process.env.VECTOR_NAME || 'fast-all-minilm-l6-v2';
    this.embeddingDimensions = parseInt(process.env.EMBEDDING_DIMENSIONS || '1024', 10);
    this.embeddingModel = process.env.EMBEDDING_MODEL || 'sentence-transformers/all-MiniLM-L6-v2';
    this.pipeline = null;
  }

  async init() {
    await this.ensureCollection(this.collectionName);
    try {
      const { pipeline } = require('@xenova/transformers');
      this.pipeline = await pipeline('feature-extraction', this.embeddingModel);
    } catch (err) {
      if (process.env.GSD_QDRANT_VERBOSE === '1') {
        console.warn('⚠️  Transformers not available, using placeholder embeddings');
      }
    }
  }

  async ensureCollection(collectionName) {
    try {
      const existing = await this.client.getCollection(collectionName);
      const vectors = existing?.config?.params?.vectors;
      const namedVector = vectors && !Array.isArray(vectors) ? vectors[this.vectorName] : null;
      if (!namedVector) throw new Error(`Collection ${collectionName} exists without named vector ${this.vectorName}. Recreate it.`);
      if (namedVector.size !== this.embeddingDimensions) throw new Error(`Collection ${collectionName} uses size ${namedVector.size}, expected ${this.embeddingDimensions}.`);
      return;
    } catch (err) {
      if (err.status === 404) {
        await this.client.createCollection(collectionName, {
          vectors: { [this.vectorName]: { size: this.embeddingDimensions, distance: 'Cosine' } },
        });
        return;
      }
      throw err;
    }
  }

  async syncAll() {
    const summary = await this.syncToGsdMemory();
    console.log(`✅ Sync complete! Total points indexed: ${summary.total}`);
    return summary;
  }

  indexedFileKey(type, relPath) {
    // Use a delimiter that cannot appear in filesystem paths (ASCII 0x01)
    // This avoids ambiguity when paths contain underscores (e.g. src/gsd_qdrant_mcp/index.js)
    return `indexed_${type}\x01${relPath}`;
  }

  async syncToGsdMemory() {
    console.log('📦 Syncing to unified gsd_memory collection...');
    const gsdDir = join(PROJECT_ROOT, '.gsd');
    const hasGsdDir = existsSync(gsdDir);

    if (!hasGsdDir) {
      console.log('  ℹ️  .gsd directory not found - indexing code only');
    }

    // Check if collection exists and has points. If empty, force full re-index.
    let collectionEmpty = false;
    try {
      const countResult = await this.client.count(this.collectionName);
      const total = countResult.count ?? countResult.total ?? 0;
      if (total === 0) {
        console.log('  ⚠️  Collection is empty — forcing full re-index');
        collectionEmpty = true;
      }
    } catch (_) {
      // Collection doesn't exist yet — will be created in init()
      collectionEmpty = true;
    }

    const mdFiles = hasGsdDir ? await this.walkGsd(gsdDir) : [];
    const codeFiles = await this.walkProjectCode(PROJECT_ROOT);
    
    console.log(`📄 Found ${mdFiles.length} documentation files to index`);
    console.log(`💻 Found ${codeFiles.length} code files to index`);
    
    // First, build the document reference index (for finding related docs)
    const docIndex = hasGsdDir ? await this.buildDocReferenceIndex(gsdDir) : [];
    
    const seenIds = new Set();
    let updated = 0;
    
    // If collection is empty, reset sync state to force re-indexing all files
    const syncState = collectionEmpty ? {} : await this.loadSyncState();
    
    // Index documentation files (.md)
    for (const filePath of mdFiles) {
      const content = await fs.readFile(filePath, 'utf8');
      const relPath = this.toProjectRelative(filePath);
      const id = this.makePointId('doc', relPath);
      const hash = this.hashContent(content);
      seenIds.add(relPath);
      
      // Check if already indexed
      if (syncState[this.indexedFileKey('doc', relPath)]?.hash === hash) continue;
      
      const payload = await this.buildDocPayload(filePath, content, relPath, content);
      const vector = await this.embedText(this.buildDocText(relPath, content, payload));
      
      await this.client.upsert(this.collectionName, { points: [{ id, vector: { [this.vectorName]: vector }, payload }] });
      syncState[this.indexedFileKey('doc', relPath)] = { path: relPath, type: 'doc', hash };
      updated += 1;
    }
    
    // Index code files (with related docs)
    for (const filePath of codeFiles) {
      const content = await fs.readFile(filePath, 'utf8');
      const relPath = this.toProjectRelative(filePath);
      const id = this.makePointId('code', relPath);
      const hash = this.hashContent(content);
      seenIds.add(relPath);
      
      // Check if already indexed
      if (syncState[this.indexedFileKey('code', relPath)]?.hash === hash) continue;
      
      const payload = await this.buildCodePayload(filePath, content, relPath, docIndex);
      const vector = await this.embedText(this.buildCodeText(relPath, content, payload));
      
      await this.client.upsert(this.collectionName, { points: [{ id, vector: { [this.vectorName]: vector }, payload }] });
      syncState[this.indexedFileKey('code', relPath)] = { path: relPath, type: 'code', hash };
      updated += 1;
    }
    
    let deleted = await this.deleteMissingPoints(seenIds, syncState);
    
    // Second pass: scan all points in the collection for this project and delete any
    // that no longer have a corresponding file on disk. This catches orphans whose
    // syncState entry was lost (corrupted state, manual file deletion, etc.).
    const staleOrphans = await this.deleteStaleProjectPoints(seenIds);
    deleted += staleOrphans;
    
    syncState.lastSync = new Date().toISOString();
    await this.saveSyncState(syncState);
    
    console.log(`  ✅ Updated ${updated}, deleted ${deleted}`);
    return { total: mdFiles.length + codeFiles.length, updated, deleted };
  }

  async searchWithContext(query, options = {}) {
    const limit = options.limit || 10;
    const vector = await this.embedText(query);

    // Prefetch-based search: broad candidate gathering then refine with score threshold
    const t0 = Date.now();
    const prefetchLimit = Math.max(limit * 3, 20);
    const SCORE_THRESHOLD = options.scoreThreshold || 0.6;

    let hits = [];
    try {
      hits = await this.client.search(this.collectionName, { 
        vector: { name: this.vectorName, vector },
        prefetch: {
          query: { name: this.vectorName, vector },
          limit: prefetchLimit,
        },
        limit: Math.min(limit * 2, prefetchLimit),
        score_threshold: SCORE_THRESHOLD,
        with_payload: true, 
        with_vector: false
      });
    } catch (prefetchErr) {
      // Fallback: plain search if prefetch fails (e.g. version incompatibility)
      if (process.env.GSD_QDRANT_VERBOSE === '1') {
        console.warn('[qdrant] prefetch not supported, falling back to search');
      }
      hits = await this.client.search(this.collectionName, { 
        vector: { name: this.vectorName, vector }, 
        limit,
        with_payload: true, 
        with_vector: false
      });
    }

    const elapsed = Date.now() - t0;
    if (process.env.GSD_QDRANT_VERBOSE === '1') {
      console.log('[qdrant] searchWithContext: %d results in %dms', hits.length, elapsed);
    }

    // Filter results locally
    let filtered = hits;
    if (options.type) {
      filtered = filtered.filter(h => h.payload.type === options.type);
    }
    
    return filtered.map((hit) => ({ score: hit.score, ...hit.payload }));
  }

  /**
   * Delete ALL points belonging to this project from the collection.
   * Uses server-side filter so only points with matching project_id are ever fetched.
   * Called during uninstall to clean up Qdrant before removing local artifacts.
   */
  async deleteAllProjectPoints() {
    let deleted = 0;
    const BATCH_SIZE = 100;

    let hasMore = true;
    while (hasMore) {
      const scrollResult = await this.client.scroll(this.collectionName, {
        limit: BATCH_SIZE,
        with_payload: false,
        with_vector: false,
        filter: {
          must: [
            { key: 'project_id', match: { value: this.projectName } }
          ]
        }
      });

      if (scrollResult.points.length === 0) {
        hasMore = false;
        break;
      }

      const pointIds = scrollResult.points.map(p => p.id);
      await this.client.delete(this.collectionName, { points: pointIds });
      deleted += pointIds.length;

      if (scrollResult.points.length < BATCH_SIZE) {
        hasMore = false;
      }
    }

    return deleted;
  }

  startWatcher() { console.log('👀 Watch mode not implemented yet. Run `gsd-qdrant-knowledge` or `node src/sync-knowledge.js`.'); }
  async walkGsd(dir) {
    const files = [];
    for (const entry of await fs.readdir(dir, { withFileTypes: true })) {
      const fullPath = join(dir, entry.name);
      if (entry.isDirectory()) {
        files.push(...await this.walkGsd(fullPath));
      } else if (entry.isFile() && entry.name.endsWith('.md')) {
        // Skip GSD project files - they are managed locally by GSD
        // GSD is the source of truth for the current project; Qdrant is an enhancer
        if (GSD_PROJECT_FILES.has(entry.name)) {
          continue;
        }
        files.push(fullPath);
      }
    }
    return files;
  }
  async walkProjectCode(dir) {
    const files = [];
    for (const entry of await fs.readdir(dir, { withFileTypes: true })) {
      const fullPath = join(dir, entry.name);
      if (entry.isDirectory()) {
        if (EXCLUDED_DIRS.has(entry.name)) continue;
        files.push(...await this.walkProjectCode(fullPath));
        continue;
      }
      if (!entry.isFile()) continue;
      if (entry.name === 'package-lock.json') continue;
      const ext = extname(entry.name).toLowerCase();
      if (EXCLUDED_FILE_EXTENSIONS.has(ext) || !CODE_EXTENSIONS.has(ext)) continue;
      
      // Also skip GSD project files found in project root
      if (entry.name.endsWith('.md') && !this.shouldIndexGsdFile(entry.name)) {
        continue;
      }
      
      files.push(fullPath);
    }
    return files;
  }
  async buildDocReferenceIndex(gsdDir) {
    const allDocs = [];
    for (const filePath of await this.walkGsd(gsdDir)) {
      const content = await fs.readFile(filePath, 'utf8');
      const relPath = this.toProjectRelative(filePath);
      const title = this.extractMetadata(filePath, content).title || basename(filePath);
      const ids = this.extractGsdIds(relPath, content);
      const keywords = this.buildKeywords(relPath, content, ids);
      allDocs.push({ path: relPath, title, ids, keywords });
    }
    return allDocs;
  }
  
  /**
   * Check if a .md file should be indexed in Qdrant
   * GSD project files are managed locally - Qdrant is for cross-project sharing only
   */
  shouldIndexGsdFile(filePath) {
    const basename = filePath.split(/[/\\]/).pop();
    return !GSD_PROJECT_FILES.has(basename);
  }
  findRelatedDocsForCode(codeRelPath, codeContent, docIndex) {
    const codeIds = new Set(this.extractGsdIds(codeRelPath, codeContent));
    const lowerPath = codeRelPath.toLowerCase();
    const contentSlice = codeContent.toLowerCase().slice(0, 4000);
    const scored = [];
    for (const doc of docIndex) {
      let score = 0;
      const reasons = [];
      if (doc.ids.some((id) => codeIds.has(id))) {
        score += 6;
        reasons.push('shared-gsd-id');
      }
      for (const id of doc.ids) {
        if (lowerPath.includes(id.toLowerCase())) {
          score += 4;
          reasons.push('path-id-match');
          break;
        }
      }
      for (const keyword of doc.keywords) {
        if (keyword.length < 4) continue;
        if (lowerPath.includes(keyword) || contentSlice.includes(keyword)) {
          score += 1;
          reasons.push(`keyword:${keyword}`);
          if (score >= 10) break;
        }
      }
      if (score > 0) scored.push({ ...doc, score, reason: [...new Set(reasons)].join(',') });
    }
    scored.sort((a, b) => b.score - a.score || a.path.localeCompare(b.path));
    return scored.slice(0, 5);
  }
  async upsertPoint(collection, point) { await this.client.upsert(collection, { points: [point] }); }
  async deleteMissingPoints(seenIds, syncState) {
    // Collect entries to delete — use stored path and type directly instead of
    // reverse-engineering from the key (which was ambiguous with underscore-encoded paths)
    const candidates = [];
    
    for (const [key, entry] of Object.entries(syncState)) {
      // Skip reserved keys
      if (key === 'lastSync') continue;
      if (!key.startsWith('indexed_')) continue;
      
      // Skip malformed entries (legacy format without type)
      const relPath = entry.path;
      const type = entry.type;
      if (!relPath || !type) {
        // Legacy entry — try to repair by removing it (orphaned data)
        delete syncState[key];
        continue;
      }
      
      if (!seenIds.has(relPath)) {
        candidates.push({ key, relPath, type });
      }
    }
    
    if (candidates.length === 0) return 0;
    
    // Before deleting, verify these points actually belong to this project.
    // This prevents cross-project collisions when two projects share the same
    // file path (e.g., both have src/cli.js) but different content.
    const candidateIds = new Set(candidates.map(({ relPath, type }) => 
      this.makePointId(type, relPath)
    ));
    
    // Scroll points for this project only and find which candidates actually exist
    let pointsToDelete = [];
    let hasMore = true;
    while (hasMore) {
      const scrollResult = await this.client.scroll(this.collectionName, {
        limit: 200,
        with_payload: ['project_id', 'source', 'type'],
        with_vector: false,
        filter: {
          must: [
            { key: 'project_id', match: { value: this.projectName } }
          ]
        }
      });
      
      for (const point of scrollResult.points) {
        if (!candidateIds.has(point.id)) continue;
        // Verify project_id matches as a safety net
        if (point.payload?.project_id !== this.projectName) continue;
        pointsToDelete.push(point.id);
      }
      
      if (scrollResult.points.length < 200) hasMore = false;
    }
    
    if (pointsToDelete.length > 0) {
      await this.client.delete(this.collectionName, { points: pointsToDelete });
      console.log(`  🗑️  Deleted ${pointsToDelete.length} orphaned point(s) from project '${this.projectName}'`);
    }
    
    // Always clean up syncState for candidates we attempted to delete
    for (const { key } of candidates) delete syncState[key];
    
    return pointsToDelete.length;
  }

  /**
   * Second-pass orphan cleanup: scan points belonging to THIS project only and delete any
   * that no longer have a corresponding file on disk.
   * Filters by project_id so other projects' points are never touched.
   */
  async deleteStaleProjectPoints(seenIds) {
    let deleted = 0;
    const BATCH_SIZE = 50;
    
    // Scroll only points belonging to this project via Qdrant filter
    let hasMore = true;
    while (hasMore) {
      const scrollResult = await this.client.scroll(this.collectionName, {
        limit: BATCH_SIZE,
        with_payload: ['project_id', 'source', 'type'],
        with_vector: false,
        filter: {
          must: [
            {
              key: 'project_id',
              match: { value: this.projectName }
            }
          ]
        }
      });
      
      if (scrollResult.points.length === 0) {
        hasMore = false;
        break;
      }
      
      const pointsToDelete = [];
      for (const point of scrollResult.points) {
        // Double-check project_id as a safety net
        if (point.payload?.project_id !== this.projectName) continue;
        
        const relPath = point.payload?.source;
        const type = point.payload?.type;
        if (!relPath || !type) continue;
        
        // If the file is still on disk, skip it
        if (seenIds.has(relPath)) continue;
        
        pointsToDelete.push(point.id);
      }
      
      if (pointsToDelete.length > 0) {
        await this.client.delete(this.collectionName, { points: pointsToDelete });
        deleted += pointsToDelete.length;
        console.log(`  🗑️  Deleted ${pointsToDelete.length} stale point(s) from project '${this.projectName}'`);
      }
      
      if (scrollResult.points.length < BATCH_SIZE) {
        hasMore = false;
      }
    }
    
    return deleted;
  }

  inferType(filePath, content) {
    if (filePath.includes('STATE.md')) return 'state';
    if (filePath.includes('REQUIREMENTS.md')) return 'requirements';
    if (filePath.includes('DECISIONS.md')) return 'decision';
    if (filePath.includes('KNOWLEDGE.md')) return 'knowledge';
    if (content.includes('## Active Milestone') || content.includes('## Current State')) return 'activity';
    return 'context';
  }

  async buildDocPayload(filePath, content, relPath, fullContent) {
    const metadata = this.extractMetadata(filePath, content);
    return {
      project_id: this.projectName,
      type: 'doc',
      subtype: this.inferType(filePath, content),
      source: relPath,
      section: this.inferSection(content),
      content: content,
      summary: metadata.title || basename(filePath),
      title: metadata.title || basename(filePath),
      language: 'markdown',
      reusable: await this.isReusable(filePath, fullContent || content),
      tags: this.extractTags(content),
      importance: this.calculateImportance(filePath, content),
      timestamp: Date.now(),
      hash: this.hashContent(content)
    };
  }

  async buildCodePayload(filePath, content, relPath, docIndex = null) {
    const metadata = this.extractCodeMetadata(filePath, content, relPath);
    const lang = this.detectLanguage(filePath);
    
    // Extract only function/class signatures (not full body)
    const signatures = this.extractSignatures(content);
    
    // Extract comments (JSDoc, single-line, multi-line) - these act as semantic summaries
    const comments = this.extractComments(content);
    
    // Extract GSD IDs from code file (M003, S01, T02, etc.)
    const snippetIds = this.extractGsdIds(relPath, content);
    
    // Find related documentation files based on shared GSD IDs
    let relatedDocPaths = [];
    let relatedDocIds = [];
    if (docIndex && docIndex.length > 0) {
      const docMatches = this.findRelatedDocsForCode(relPath, content, docIndex);
      relatedDocPaths = docMatches.map(d => d.path);
      relatedDocIds = docMatches.flatMap(d => d.ids);
    }
    
    return {
      project_id: this.projectName,
      type: 'code',
      language: lang,
      source: relPath,
      summary: metadata.name || basename(filePath),
      kindDetail: metadata.kindDetail,
      scope: metadata.scope,
      workspace: metadata.workspace,
      content: content, // Keep full content for reference
      signatures: signatures, // Only signatures for embedding
      exports: metadata.exports,
      imports: metadata.imports,
      symbolNames: metadata.symbolNames,
      comments: comments, // JSDoc and comments for semantic context
      relatedDocPaths: relatedDocPaths, // Related documentation files
      relatedDocIds: relatedDocIds, // Related GSD IDs from docs
      timestamp: Date.now(),
      hash: this.hashContent(content)
    };
  }

  extractSignatures(content) {
    const signatures = [];
    
    // Function declarations: function name(params) { }
    const funcDecls = content.match(/function\s+([A-Za-z_$][A-Za-z0-9_$]*)\s*\([^)]*\)/g) || [];
    signatures.push(...funcDecls);
    
    // Class declarations: class Name { }
    const classDecls = content.match(/class\s+([A-Za-z_$][A-Za-z0-9_$]*)/g) || [];
    signatures.push(...classDecls);
    
    // Method declarations: methodName(params) { }
    const methodDecls = content.match(/[A-Za-z_$][A-Za-z0-9_$]*\s*\([^)]*\)\s*{/g) || [];
    signatures.push(...methodDecls.filter(m => !m.includes('function') && !m.includes('class')));
    
    // Arrow functions: const name = (params) =>
    const arrowFuncs = content.match(/const\s+[A-Za-z_$][A-Za-z0-9_$]*\s*=\s*\([^)]*\)\s*=>/g) || [];
    signatures.push(...arrowFuncs);
    
    // Async functions: async function name
    const asyncFuncs = content.match(/async\s+function\s+([A-Za-z_$][A-Za-z0-9_$]*)/g) || [];
    signatures.push(...asyncFuncs);
    
    return [...new Set(signatures)].slice(0, 50); // Limit to avoid large embeddings
  }

  extractComments(content) {
    const comments = [];
    
    // JSDoc comments: /** ... */
    const jsdoc = content.match(/\/\*\*[\s\S]*?\*\/|\/\*\*[\s\S]*?\*$/g) || [];
    comments.push(...jsdoc);
    
    // Single-line comments: // ...
    const singleLine = content.match(/\/\/[^\n]{0,200}/g) || [];
    comments.push(...singleLine);
    
    // Multi-line comments: /* ... */
    const multiLine = content.match(/\/\*[\s\S]{0,500}\*\//g) || [];
    comments.push(...multiLine);
    
    return comments.slice(0, 30); // Limit to avoid large embeddings
  }

  inferSection(content) {
    if (content.includes('## Active Milestone')) return 'current_state';
    if (content.includes('## Milestone Registry')) return 'milestone_registry';
    if (content.includes('## Recent Decisions')) return 'recent_decisions';
    if (content.includes('## Blockers')) return 'blockers';
    if (content.includes('## Next Action')) return 'next_action';
    if (content.includes('## Requirements')) return 'requirements';
    if (content.includes('## Decisions')) return 'decisions';
    if (content.includes('## Knowledge')) return 'knowledge';
    return 'general';
  }

  async isReusable(filePath, content) {
    // For documentation files: DECISIONS.md and KNOWLEDGE.md are always reusable
    if (filePath.includes('DECISIONS.md') || filePath.includes('KNOWLEDGE.md')) {
      return true;
    }
    
    // For code files: consider reusable if the file exports something
    const ext = extname(filePath).toLowerCase();
    if (CODE_EXTENSIONS.has(ext)) {
      const hasExport = /export\s+(default\s+)?(?:async\s+)?(?:function|class|const|let|var)/.test(content);
      const hasModuleExports = /module\.exports\s*=/.test(content);
      const hasExports = /exports\.[A-Za-z_]/.test(content);
      
      if (hasExport || hasModuleExports || hasExports) {
        return true;
      }
    }
    
    return false;
  }

  extractTags(content) {
    const tags = [];
    if (content.includes('## Decisions')) tags.push('decision');
    if (content.includes('## Knowledge')) tags.push('knowledge');
    if (content.includes('Active Milestone')) tags.push('active');
    if (content.includes('## Requirements')) tags.push('requirements');
    return tags;
  }

  calculateImportance(filePath, content) {
    if (filePath.includes('STATE.md')) return 5;
    if (filePath.includes('REQUIREMENTS.md')) return 5;
    if (filePath.includes('DECISIONS.md')) return 4;
    if (filePath.includes('KNOWLEDGE.md')) return 3;
    return 2;
  }

  buildDocText(relPath, content, metadata) {
    return [`project:${this.projectName}`, `path:${relPath}`, metadata.title ? `title:${metadata.title}` : null, content].filter(Boolean).join('\n');
  }

  buildCodeText(relPath, content, payload) {
    // For code embedding, use signatures + comments (semantic summary)
    const sigText = payload.signatures.join('\n');
    const exportText = payload.exports ? `exports:${payload.exports.join(', ')}` : null;
    const importText = payload.imports ? `imports:${payload.imports.join(', ')}` : null;
    const symbolText = payload.symbolNames ? `symbols:${payload.symbolNames.join(', ')}` : null;
    const commentText = payload.comments ? `comments:${payload.comments.join(' | ')}` : null;
    
    return [
      `project:${this.projectName}`,
      `path:${relPath}`,
      `language:${payload.language}`,
      `kind:${payload.kindDetail}`,
      exportText,
      importText,
      symbolText,
      commentText,
      sigText
    ].filter(Boolean).join('\n');
  }
  async embedText(text) { if (this.pipeline) { const output = await this.pipeline(text, { pooling: 'mean', normalize: true }); return Array.from(output.data); } return this.generatePlaceholderEmbedding(text); }
  extractMetadata(filePath, content) { const metadata = { relativePath: this.toProjectRelative(filePath) }; const titleMatch = content.match(/^#\s+(.+)$/m); if (titleMatch) metadata.title = titleMatch[1].trim(); const frontmatterMatch = content.match(/^---\n([\s\S]*?)\n---/); if (frontmatterMatch) { const dateMatch = frontmatterMatch[1].match(/date:\s+(.+)/); if (dateMatch) metadata.date = dateMatch[1].trim(); } return metadata; }
  extractGsdIds(relPath, content) { const matches = new Set(); for (const source of [relPath, content]) { const found = source.match(/\b(M\d{3}|S\d{2}|T\d{2}|R\d{3}|D\d{3})\b/g) || []; found.forEach((m) => matches.add(m)); } return [...matches]; }
  extractReferencedPaths(content) { return [...new Set(content.match(/[\w./-]+\.[a-z]{2,4}/gi) || [])].slice(0, 20); }
  buildKeywords(relPath, content, ids) { return [...new Set([relPath, ...ids, ...((content.match(/\b[a-zA-Z][a-zA-Z0-9_-]{3,}\b/g) || []).slice(0, 80))].map((value) => value.toLowerCase()))]; }
  detectLanguage(filePath) { const ext = extname(filePath).toLowerCase(); const byExt = { '.js':'javascript','.jsx':'javascript','.mjs':'javascript','.cjs':'javascript','.ts':'typescript','.tsx':'typescript','.py':'python','.rb':'ruby','.php':'php','.go':'go','.rs':'rust','.java':'java','.kt':'kotlin','.cs':'csharp','.swift':'swift','.html':'html','.css':'css','.scss':'scss','.sql':'sql','.sh':'shell','.bash':'shell','.zsh':'shell','.ps1':'powershell','.json':'json','.yaml':'yaml','.yml':'yaml','.vue':'vue','.svelte':'svelte','.astro':'astro' }; return byExt[ext] || ext.replace('.', '') || 'text'; }
  detectScope(relPath) { const path = relPath.replace(/\\/g, '/').toLowerCase(); if (path.includes('/test') || path.includes('.test.') || path.includes('.spec.')) return 'test'; if (path.includes('/scripts/')) return 'script'; if (path.includes('/components/')) return 'component'; if (path.includes('/pages/') || path.includes('/app/')) return 'page'; if (path.includes('/api/') || path.includes('/routes/')) return 'api'; return 'code'; }
  extractCodeMetadata(filePath, content, relPath) { const baseName = basename(filePath, extname(filePath)); const exportMatches = [...content.matchAll(/export\s+(?:default\s+)?(?:async\s+)?(?:function|class|const|let|var)?\s*([A-Za-z_][\w$]*)?/g)].map((m) => m[1]).filter(Boolean); const commonJsExports = [...content.matchAll(/module\.exports\s*=\s*([A-Za-z_][\w$]*)|exports\.([A-Za-z_][\w$]*)\s*=/g)].map((m) => m[1] || m[2]).filter(Boolean); const importMatches = [...content.matchAll(/import\s+(?:[^'"\n]+\s+from\s+)?['"]([^'"]+)['"]|require\(['"]([^'"]+)['"]\)/g)].map((m) => m[1] || m[2]).filter(Boolean); const symbolNames = [...new Set([
    ...exportMatches,
    ...commonJsExports,
    ...[...content.matchAll(/(?:function|class|const)\s+([A-Za-z_][\w$]*)/g)].slice(0, 20).map((m) => m[1]),
  ])]; const scope = this.detectScope(relPath); const workspace = relPath.split('/')[0] || '.'; const name = symbolNames[0] || baseName; let kindDetail = scope; if (/\.tsx?$/.test(filePath) && /<[A-Z][A-Za-z0-9]*/.test(content)) kindDetail = 'react-component'; else if (scope === 'api') kindDetail = 'api-module'; else if (scope === 'script') kindDetail = 'script'; else if (/use[A-Z]/.test(name)) kindDetail = 'hook'; return { name, symbolNames, exports: [...new Set([...exportMatches, ...commonJsExports])], imports: [...new Set(importMatches)].slice(0, 50), workspace, kindDetail }; }
  generatePlaceholderEmbedding(content) { const hash = crypto.createHash('md5').update(content).digest('hex'); const vector = new Array(this.embeddingDimensions).fill(0); for (let i = 0; i < this.embeddingDimensions; i++) { const startIdx = (i * 4) % hash.length; const hashPart = hash.substring(startIdx, startIdx + 4) || hash.substring(0, 4); vector[i] = parseInt(hashPart, 16) / 0xffff; } const norm = Math.sqrt(vector.reduce((sum, val) => sum + val * val, 0)); if (norm > 0 && !Number.isNaN(norm)) for (let i = 0; i < this.embeddingDimensions; i++) vector[i] /= norm; return vector; }
  makePointId(kind, relPath) { return parseInt(crypto.createHash('md5').update(`${this.projectName}\x01${kind}:${relPath}`).digest('hex').substring(0, 8), 16); }
  hashContent(content) { return crypto.createHash('md5').update(content).digest('hex'); }
  toProjectRelative(filePath) { return relative(PROJECT_ROOT, filePath).replace(/\\/g, '/'); }
  async loadSyncState() {
    try {
      const content = await fs.readFile(STATE_FILE, 'utf8');
      return JSON.parse(content);
    } catch (_) {
      return { lastSync: null };
    }
  }
  async saveSyncState(state) {
    const dir = dirname(STATE_FILE);
    await fs.mkdir(dir, { recursive: true });
    await fs.writeFile(STATE_FILE, JSON.stringify(state, null, 2));
  }
}

