export function getWordPressUrl(): string | undefined {
  const u = process.env.WORDPRESS_URL?.trim();
  return u ? u.replace(/\/$/, "") : undefined;
}

/** GraphQL endpoint for WPGraphQL + WooCommerce (full URL). */
export function getWordPressGraphqlUrl(): string | undefined {
  const g = process.env.WORDPRESS_GRAPHQL_URL?.trim();
  if (g) return g;
  const a = process.env.WORDPRESS_API_URL?.trim();
  return a || undefined;
}

export function isWooGraphqlConfigured(): boolean {
  return Boolean(getWordPressGraphqlUrl());
}

/**
 * Use WPGraphQL WooCommerce cart (httpOnly session cookie + /api/shop/cart).
 * Requires the WPGraphQL for WooCommerce plugin. Default is false so catalog-via-REST
 * setups still get a working browser cart; set WOO_USE_GRAPHQL_CART=true when that plugin is active.
 */
export function useWooGraphqlSessionCart(): boolean {
  if (process.env.WOO_USE_GRAPHQL_CART?.trim().toLowerCase() !== "true") {
    return false;
  }
  return isWooGraphqlConfigured();
}

